{"file_path":"/home/user/workspace/app/admin/catalog/page.tsx","content":"import { cacheTag, revalidateTag } from 'next/cache'
import type { Metadata } from 'next'
import { getAllProducts } from '@/lib/db'

export const metadata: Metadata = {
  title: 'Product Catalog — Admin',
}

async function getCachedProducts() {
  'use cache'
  cacheTag('products')

  return getAllProducts()
}

export default async function CatalogPage() {
  async function syncCatalog(formData: FormData) {
    'use server'

    // The actual full catalog sync (hundreds/thousands of SKUs from
    // upstream ERP/PIM) runs as a background job.  We return
    // immediately so the operator can keep working.
    //
    // Using stale-while-revalidate ("max" profile) means the current
    // cached data continues to be served while fresh data is fetched
    // in the background — eventual consistency across any view that
    // uses the "products" tag.
    revalidateTag('products', 'max')
  }

  const products = await getCachedProducts()

  return (
    <div>
      <h1>Product Catalog</h1>

      <form action={syncCatalog}>
        <button type="submit">Sync latest catalog</button>
      </form>

      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Price</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td>{product.id}</td>
              <td>{product.name}</td>
              <td>${product.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
"}

